from langgraph.graph import END, START

@node
def merge_retrievals(state):
    chunks = state['retrievers_output']
    chunk_texts = [c.page_content for c in chunks]

    overlaps = 0
    for i in range(len(chunk_texts)):
        for j in range(i+1, len(chunk_texts)):
            if chunk_texts[i][:100] == chunk_texts[j][:100]:
                overlaps += 1

    state['overlap_ratio'] = overlaps / (len(chunks) * (len(chunks)-1) / 2)
    return state

