import numpy as np
from langgraph.prebuilt import create_react_agent

@observer
def trace_embedding_drift(state, config):
    if 'embedding_history' not in config:
        config['embedding_history'] = []

    current_emb = np.mean(state['retrieved_chunks'].embeddings, axis=0)
    config['embedding_history'].append(current_emb)

    if len(config['embedding_history']) > 1:
        cosine_sim = np.dot(
            config['embedding_history'][-1], 
            config['embedding_history'][-2]
        ) / (
            np.linalg.norm(config['embedding_history'][-1]) * 
            np.linalg.norm(config['embedding_history'][-2])
        )
        return cosine_sim < 0.7  # Alert threshold
    return False

