from langgraph.checkpoint.base import BaseCheckpointSaver
import json

class SchemaAwareSaver(BaseCheckpointSaver):
    def __init__(self, *args, schema_version='v2', **kwargs):
        super().__init__(*args, **kwargs)
        self.schema_version = schema_version

    def put(
        self, config, checkpoint, metadata
    ) -> dict[str, str | int | float | None]:
        checkpoint['schema_version'] = self.schema_version
        # Migrate old chunk metadata schema
        if 'old_chunks' in checkpoint:
            checkpoint['chunks'] = [
                {**c, 'metadata_v2': c.get('metadata', {})} 
                for c in checkpoint['old_chunks']
            ]
        return super().put(config, checkpoint, metadata)

# Usage: graph = StateGraph(State).compile(checkpointer=SchemaAwareSaver())

from langgraph.graph import StateGraph

class QualityState(TypedDict):
    chunks: list
    avg_score: float
    needs_human_review: bool

@condition
def quality_gate(state: QualityState):
    avg_relevance = np.mean([c['score'] for c in state['chunks']])
    state['avg_score'] = avg_relevance

    if avg_relevance < 0.75:
        state['needs_human_review'] = True
        return 'human_review'
    return 'continue_agent'

# Graph wiring
graph.add_conditional_edges(
    'retrieve', 
    quality_gate,
    {'human_review': 'human_feedback_node', 'continue_agent': 'agent'}
)

